}

/* ── My Projects Page ── */
function MyProjectsPage({ projects, allIssues }) {
  return (
    <>
      <div className="page-header"><h1>My Projects</h1><p>{projects.length} project{projects.length !== 1 ? 's' : ''} assigned to you</p></div>
      {projects.length === 0 ? (
